solution: class Solution {
public:
    bool canPartitionKSubsets(vector<int>& nums, int k) {
        int total = accumulate(nums.begin(), nums.end(), 0);
        if (total % k) return false;
        int target = total / k;
        sort(nums.rbegin(), nums.rend());
        if (nums[0] > target) return false;
        vector<int> groups(k, 0);
        return dfs(nums, 0, groups, target);
    }
private:
    bool dfs(const vector<int>& nums, int idx, vector<int>& groups, int target) {
        if (idx == nums.size()) return true;
        int val = nums[idx];
        for (int i = 0; i < groups.size(); ++i) {
            if (groups[i] + val > target) continue;
            if (i && groups[i] == groups[i-1]) continue;
            groups[i] += val;
            if (dfs(nums, idx + 1, groups, target)) return true;
            groups[i] -= val;
            if (groups[i] == 0) break;
        }
        return false;
    }
};
